class Codec:
    def serialize(self, root):
        tokens = []
        def dfs(node):
            if node is None:
                tokens.append('#')
                return
            tokens.append(str(node.val))
            dfs(node.left)
            dfs(node.right)
        dfs(root)
        return ','.join(tokens)

    def deserialize(self, data):
        it = iter(data.split(','))
        def build():
            token = next(it)
            if token == '#':
                return None
            node = TreeNode(int(token))
            node.left = build()
            node.right = build()
            return node
        return build()

