var serialize = function(root) {
    const tokens = [];
    const dfs = (node) => {
        if (!node) {
            tokens.push('#');
            return;
        }
        tokens.push(String(node.val));
        dfs(node.left);
        dfs(node.right);
    };
    dfs(root);
    return tokens.join(',');
};

var deserialize = function(data) {
    const it = data.split(',')[Symbol.iterator]();
    const build = () => {
        const token = it.next().value;
        if (token === '#') return null;
        const node = new TreeNode(parseInt(token, 10));
        node.left = build();
        node.right = build();
        return node;
    };
    return build();
};
